/*
 * This file was generated by the Gradle 'init' task.
 *
 * The settings file is used to specify which projects to include in your build.
 * For more detailed information on multi-project builds, please refer to https://docs.gradle.org/9.2.1/userguide/multi_project_builds.html in the Gradle documentation.
 * This project uses @Incubating APIs which are subject to change.
 */

// The settings file is the entry point of every Gradle build.
// Its primary purpose is to define the subprojects.
// It is also used for some aspects of project-wide configuration, like managing plugins, dependencies, etc.
// https://docs.gradle.org/current/userguide/settings_file_basics.html
pluginManagement {
    // Include 'plugins build' to define convention plugins.
    includeBuild("build-logic")

    repositories {
        mavenCentral()
        gradlePluginPortal()
    }
}

plugins {
    // Use the Foojay Toolchains plugin to automatically download JDKs required by subprojects.
    id("org.gradle.toolchains.foojay-resolver-convention") version "1.0.0"
}

@Suppress("UnstableApiUsage")
dependencyResolutionManagement {
    repositoriesMode.set(RepositoriesMode.FAIL_ON_PROJECT_REPOS)
    // Use Maven Central as the default repository (where Gradle will download dependencies) in all subprojects.
    repositories {
        mavenCentral()
    }
}

rootProject.name = "kogot"

enableFeaturePreview("TYPESAFE_PROJECT_ACCESSORS")

// If there are changes in only one of the projects, Gradle will rebuild only the one that has changed.
// Learn more about structuring projects with Gradle - https://docs.gradle.org/8.7/userguide/multi_project_builds.html

// JVM using FFM API
include(
    "jvm-ffm-ffm",
    "jvm-ffm-api",
    "jvm-ffm-runtime",
)

project(":jvm-ffm-ffm").projectDir = file("jvm-ffm/ffm")
project(":jvm-ffm-api").projectDir = file("jvm-ffm/api")
project(":jvm-ffm-runtime").projectDir = file("jvm-ffm/runtime")

// Kotlin using Native Cinterop
include(
    "kotlin-native-ffm",
    "kotlin-native-api",
    "kotlin-native-runtime",
)

project(":kotlin-native-ffm").projectDir = file("kotlin-native/ffm")
project(":kotlin-native-api").projectDir = file("kotlin-native/api")
project(":kotlin-native-runtime").projectDir = file("kotlin-native/runtime")

// codegen and processor
include("codegen", "processor")
